Here is a simple C program that creates a file called “myfile.txt” and writes a string to it, then opens it again to print it out.

fopen:	Opens a file with the given path. The		string that follows is the access mode.		“w+” opens for writing; overwrites file. 		“r” opens read-only.
fread:	Reads to the provided buffer the given		number of bytes. (The “1” is the number 		of elements to read if reading an array.)
fwrite:	Writes from the provided buffer the given		number of bytes. (Similar to fread)
fseek:	Moves the current file position.
ftell:	Returns the current file position.

#include <stdio.h>   // for fopen, fread, etc
#include <string.h>

void main(void) {
  const char* path = "myfile.txt";
  const char* data = "hello!";
  char buffer[100] = {0};

  FILE* f = fopen(path, "w+");
  fwrite(data, strlen(data), 1, f);
  fclose(f);

  FILE* f2 = fopen(path, "r");
  fseek(f2, 0, SEEK_END);
  size_t filesize = ftell(f2);
  fseek(f2, 0, SEEK_SET);
  fread(buffer, filesize, 1, f2);
  buffer[filesize] = '\0';
  fclose(f2);

  printf("The file says: %s\n", buffer);
}
